import pytest
import requests

def test_hr_admin_deletes_existing_leave_request_returns_200_and_audit(
    hr_admin_token, api_base_url, create_leave_request, get_audit_record
):
    leave_id = create_leave_request(hr_admin_token)
    headers = {"Authorization": f"Bearer {hr_admin_token}"}

    response = requests.delete(
        f"{api_base_url}/api/leave-requests/{leave_id}",
        headers=headers,
    )

    assert response.status_code in (200, 201), (
        f"Expected 200 or 201, got {response.status_code}: {response.text}"
    )
    body = response.json()
    assert str(leave_id) in str(body), (
        f"Entity id {leave_id} not found in response body"
    )
    audit = get_audit_record(entity_id=leave_id, action="delete")
    assert audit is not None, "Audit record not written for delete action"

import pytest
import requests

def test_delete_non_existent_leave_request_returns_400_or_404(
    hr_admin_token, api_base_url, nonexistent_leave_id, get_audit_record
):
    bad_id = nonexistent_leave_id()
    headers = {"Authorization": f"Bearer {hr_admin_token}"}

    response = requests.delete(
        f"{api_base_url}/api/leave-requests/{bad_id}",
        headers=headers,
    )

    assert response.status_code in (400, 404), (
        f"Expected 400 or 404 for non-existent id, got {response.status_code}: {response.text}"
    )
    audit = get_audit_record(entity_id=bad_id, action="delete")
    assert audit is None, "Audit record must not be written for a failed delete"

import pytest
import requests

def test_delete_already_deleted_leave_request_state_transition(
    hr_admin_token, api_base_url, create_leave_request, get_audit_record
):
    leave_id = create_leave_request(hr_admin_token)
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    url = f"{api_base_url}/api/leave-requests/{leave_id}"

    first = requests.delete(url, headers=headers)
    assert first.status_code in (200, 201), (
        f"First delete failed: {first.status_code} {first.text}"
    )

    second = requests.delete(url, headers=headers)
    assert second.status_code in (400, 404), (
        f"Expected 400 or 404 on re-delete, got {second.status_code}: {second.text}"
    )
    audits = get_audit_record(entity_id=leave_id, action="delete", all_records=True)
    assert len(audits) == 1, (
        f"Expected exactly 1 audit record, found {len(audits)}"
    )

import pytest
import requests

def test_delete_leave_request_missing_id_field_returns_400(
    hr_admin_token, api_base_url
):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}

    # Omit the id entirely — targets the collection endpoint
    response = requests.delete(
        f"{api_base_url}/api/leave-requests/",
        headers=headers,
    )

    assert response.status_code == 400, (
        f"Expected 400 for missing id, got {response.status_code}: {response.text}"
    )
    body = response.json()
    error_text = str(body).lower()
    assert any(kw in error_text for kw in ("invalid", "required", "validation", "id")), (
        f"Expected validation error in body, got: {body}"
    )
